import React, { useMemo } from 'react';
import { useIntl } from 'gatsby-plugin-intl';
import { graphql } from 'gatsby';
import Image from 'gatsby-image';
import { makeStyles } from '@material-ui/core/styles';
import { Typography } from '@material-ui/core';

// Utils
import { getAlternateLangLinks } from '../utils/gatsby-frontend-helpers';

// Components
import Layout from '../components/Layout';
import SEO from '../components/SEO';

const useStyles = makeStyles((theme) => ({
    aboutWrapper: {
        [theme.breakpoints.up('lg')]: {
            display: 'flex',
        },
        padding: '15px 5px',
    },
    aboutImageWrapper: {
        [theme.breakpoints.up('lg')]: {
            minWidth: '400px',
        },
        [theme.breakpoints.down('lg')]: {
            width: '100% !important', // TODO
        },
    },
    aboutText: {
        margin: '15px 0',
    },
    aboutMeTextWrapper: {
        padding: '24px',
    },
}));

const About = ({ location, data, pageContext }) => {
    const { aboutPic } = data;
    const intl = useIntl();
    const classes = useStyles();
    const alternateLangLinks = useMemo(
        () => getAlternateLangLinks(pageContext, data.site.siteMetadata.siteUrl),
        [data.site.siteMetadata.siteUrl, pageContext]
    );

    return (
        <Layout>
            <SEO
                lang={intl.locale}
                pathname={location?.pathname}
                title={intl.formatMessage({ id: 'about' })}
                ogImage={aboutPic.childImageSharp.fluid.src}
                keywords={[
                    intl.formatMessage({ id: 'seo_keywords.about_me' }),
                    intl.formatMessage({ id: 'seo_keywords.personal_blog' }),
                    intl.formatMessage({ id: 'seo_keywords.personal_projects' }),
                    intl.formatMessage({ id: 'seo_keywords.travels' }),
                    intl.formatMessage({ id: 'seo_keywords.developer' }),
                ]}
                alternateLangLinks={alternateLangLinks}
            />
            <Typography
                className={classes.aboutText}
                color="textPrimary"
                variant="h4"
            >
                {intl.formatMessage({ id: 'about' })}
            </Typography>
            <div className={classes.aboutWrapper}>
                <Image
                    className={classes.aboutImageWrapper}
                    fluid={aboutPic.childImageSharp.fluid}
                    alt={intl.formatMessage({ id: 'thats_me' })}
                />
                <div className={classes.aboutMeTextWrapper}>
                    <Typography
                        color="textPrimary"
                        variant="h5"
                    >
                        {intl.formatMessage({ id: 'thats_me' })}
                    </Typography>
                    <Typography
                        color="textPrimary"
                    >
                        {intl.formatMessage({ id: 'about_paragraph_1' })}
                    </Typography>
                    <Typography
                        color="textPrimary"
                    >
                        {intl.formatMessage({ id: 'about_paragraph_2' })}
                    </Typography>
                </div>
            </div>
        </Layout>
    );
};

export default About;

export const pageQuery = graphql`
    query {
        aboutPic: file(absolutePath: { regex: "/about-pic.jpg/" }) {
            childImageSharp {
                fluid(maxWidth: 750) {
                    ...GatsbyImageSharpFluid_tracedSVG
                }
            }
        }
        site {
            siteMetadata {
                siteUrl
            }
        }
    }
`;
